const ctx = base.ctx || {};

const rows = $input.all().map(i => i.json || {}).filter(Boolean);
if (!rows.length) throw new Error('TVPX__30: no ready scene seeds found.');

function n(v, d = 0) {
  const x = Number(v);
  return Number.isFinite(x) ? x : d;
}

function clean(v) {
  return String(v || '').toLowerCase().replace(/[^a-z0-9\s-]/g, ' ').replace(/\s+/g, ' ').trim();
}

const hardBans = [
  'mri', 'brain scan', 'graph', 'chart', 'diagram', 'spreadsheet',
  'dashboard', 'monitor', 'contract', 'lease', 'form', 'paperwork'
];

const scored = rows.map((row) => {
  const positiveBlob = clean([
    row.scene_kernel,
    row.material_anchor,
    row.spatial_directive,
    row.dominant_subject,
    row.setting_family,
    row.surreal_mechanism
  ].join(' '));

  const hardBanHits = hardBans.filter(term => (` ${positiveBlob} `).includes(` ${clean(term)} `)).length;

  const selectorScore =
    n(row.quality_score) * 0.22 +
    n(row.brand_fit_score) * 0.16 +
    n(row.reference_alignment_score) * 0.20 +
    n(row.family_guardrail_score) * 0.16 +
    n(row.negative_space_force_score) * 0.14 +
    n(row.prop_discipline_score) * 0.12 -
    Math.min(n(row.used_count) * 0.35, 2.0) -
    hardBanHits * 1.2;

  return { row, selectorScore };
}).sort((a, b) => b.selectorScore - a.selectorScore);

