function getVal(r, ...keys) {
  if (!r) return '';
  for (const k of keys) {
    const v = r[k];
    if (v != null && String(v).trim()) return String(v).trim();
  }
  return '';
}

let owner = getVal(row, 'lock_owner', 'lockOwner');
