function extractJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('TVPX__30: empty prompt-spec output.');

  const candidates = [
    text,
    text.replace(/```json\s*/gi, '').replace(/```/g, '').trim(),
  ];

  for (const candidate of candidates) {
    try { return JSON.parse(candidate); } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');
    return JSON.parse(slice);
  }

  throw new Error('TVPX__30: could not parse prompt-spec JSON.');
}

function cleanText(v) {
  return String(v || '')
    .replace(/\s+/g, ' ')
    .replace(/\s+([,.;:!?])/g, '$1')
    .trim();
}

function wordCount(v) {
  const t = cleanText(v);
  return t ? t.split(/\s+/).length : 0;
}

function parseJsonMaybe(value, fallback) {
  if (Array.isArray(value) || (value && typeof value === 'object')) return value;
  const text = String(value || '').trim();
  if (!text) return fallback;
  try { return JSON.parse(text); } catch { return fallback; }
}

const base = $json || {};
const packet = base.prompt_smith_packet || {};
const parsed = extractJson(base.text || base.output || base.result || base);

const masterPrompt = cleanText(parsed.master_prompt || '');
if (!masterPrompt) throw new Error('TVPX__30: master_prompt missing.');

const wc = wordCount(masterPrompt);
const hardCeiling = Number(packet.family_guardrail?.render_prompt_word_ceiling || packet.render_limits?.max_prompt_words || 115);

if (wc < 80) throw new Error(`TVPX__30: master_prompt too short (${wc} words).`);
if (wc > hardCeiling) throw new Error(`TVPX__30: master_prompt too long (${wc} words). Do not trim; regenerate.`);

const shotType = cleanText(packet.locked_blueprint?.shot_type || '').toLowerCase();
const firstWords = masterPrompt.toLowerCase().split(/\s+/).slice(0, 20).join(' ');
if (shotType.includes('overhead') && !firstWords.includes('overhead')) {
  throw new Error('TVPX__30: prompt lost the locked shot family near the opening.');
}
if (shotType.includes('medium-wide') && !(firstWords.includes('medium-wide') || firstWords.includes('medium wide'))) {
  throw new Error('TVPX__30: prompt lost the locked medium-wide framing near the opening.');
}

const heroProps = parseJsonMaybe(packet.visible_scene?.prop_manifest, { hero_props: [], supporting_props: [] }).hero_props || [];
for (const prop of heroProps) {
  const needle = cleanText(prop).toLowerCase();
  if (needle && !masterPrompt.toLowerCase().includes(needle.split(' ')[0])) {
    throw new Error(`TVPX__30: hero prop missing from prompt: ${prop}`);
  }
}

const bannedPhrases = [
  'symbolic', 'allegorical', 'evoking', 'suggesting', 'representing',
  'ghostly', 'ominous', 'beautiful portrait', 'fashion editorial',
  'studio portrait', 'product shot', 'cgi sheen'
];

for (const phrase of bannedPhrases) {
  if (masterPrompt.toLowerCase().includes(phrase)) {
    throw new Error(`TVPX__30: banned phrase leaked into prompt: ${phrase}`);
  }
}

const forbiddenStyleTerms = Array.isArray(packet.family_guardrail?.forbidden_style_terms)
  ? packet.family_guardrail.forbidden_style_terms
  : [];

const negParts = []
  .concat(String(parsed.negative_prompt || '').split(',').map(s => cleanText(s)).filter(Boolean))
  .concat(forbiddenStyleTerms.map(cleanText).filter(Boolean));

const negativePrompt = [...new Set(negParts)].join(', ');

return [{
