function extractJsonText(raw) {
  const body = raw?.body ?? raw?.data ?? raw ?? {};
  if (typeof body.output_text === 'string' && body.output_text.trim()) return body.output_text;

  const chunks = [];
  const output = Array.isArray(body.output) ? body.output : [];
  for (const item of output) {
    const content = Array.isArray(item?.content) ? item.content : [];
    for (const block of content) {
      if (typeof block?.text === 'string' && block.text.trim()) chunks.push(block.text);
      if (typeof block?.output_text === 'string' && block.output_text.trim()) chunks.push(block.output_text);
    }
  }

  return chunks.join('\n') || JSON.stringify(body);
}

