function clean(v) {
  return String(v || '').toLowerCase().replace(/[^a-z0-9\s-]/g, ' ').replace(/\s+/g, ' ').trim();
}

const base = $json || {};
const pack = base.scene_blueprint_pack || {};
const guardrail = base.archetype_guardrail_row || {};
const blueprints = Array.isArray(pack.blueprints) ? pack.blueprints : [];

if (!blueprints.length) throw new Error('TVPX__30: no blueprints returned.');

function parseJsonMaybe(v, fb) { if (Array.isArray(v)) return v; if (v && typeof v === 'object') return fb; try { return JSON.parse(v); } catch { return fb; } }
const forbiddenStyleTerms = parseJsonMaybe(guardrail.forbidden_style_terms || guardrail.forbidden_style_terms_json, []);
const envTerms = parseJsonMaybe(guardrail.anchor_environment_terms || guardrail.anchor_environment_terms_json, []);

function passesGuard(bp, skipEnvCheck) {
  const shot = clean(bp.shot_type);
  const core = clean(bp.candidate_prompt_core);
  const env = clean(bp.environment);
  const full = `${shot} ${core} ${env}`;

  if (forbiddenStyleTerms.some(t => full.includes(clean(t)))) return false;
  const wordCeiling = Number(guardrail.render_prompt_word_ceiling || guardrail.render_prompt_word_ceiling_json || 115);
  if (wordCeiling > 0 && (core.split(/\s+/).filter(Boolean).length) > wordCeiling) return false;
  if (!skipEnvCheck && envTerms.length && !envTerms.some(t => full.includes(clean(t)))) return false;
  if (full.includes('studio') || full.includes('fashion editorial') || full.includes('product shot')) return false;
  return true;
}

let filtered = blueprints.filter(bp => passesGuard(bp, false));
let guard_env_relaxed = false;

if (!filtered.length && envTerms.length) {
  filtered = blueprints.filter(bp => passesGuard(bp, true));
  guard_env_relaxed = filtered.length > 0;
}

if (!filtered.length) {
  const sample = blueprints[0];
  const full = `${clean(sample?.shot_type || '')} ${clean(sample?.candidate_prompt_core || '')} ${clean(sample?.environment || '')}`;
  throw new Error('TVPX__30: all blueprint candidates failed deterministic family guard. Check: forbidden_style_terms, anchor_environment_terms, word count (>70), or hard bans (studio, fashion editorial, product shot). Sample full text length: ' + full.length);
}

return [{
  json: {
    ...base,
    scene_blueprint_pack: {
      ...pack,
      blueprints: filtered
    },
    ...(guard_env_relaxed ? { guard_env_relaxed: true } : {})
  }
}];

